// Helper component for icon import (if needed) or remove if unused icons are cleaned up
import { ChevronRight } from 'lucide-react';

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useNavigate } from 'react-router-dom';
import {
    Activity,
    Plus,
    Search,
    Filter,
    ArrowUpDown,
    Check,
    AlertTriangle,
    Clock,
    DollarSign,
    MousePointer,
    Eye,
    Target,
    BarChart3,
    ArrowUpRight,
    ArrowDownRight,
    TrendingUp,
    Zap, // Added Zap
    Sparkles, // Added Sparkles
    BrainCircuit, // Added BrainCircuit
    ChevronRight, // Added ChevronRight
    Settings,
    MoreVertical
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Badge } from '@/components/ui/badge';
import { useAuth } from '@/contexts/AuthContext';
import { formatCurrency } from '@/lib/utils';
import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const item = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0 }
};

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.05
        }
    }
};

export default function Campanhas() {
    const navigate = useNavigate();
    const { user } = useAuth();
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState('ALL');

    const { data: campaigns, isLoading } = useQuery({
        queryKey: ['campaigns', user?.company_id],
        queryFn: async () => {
            if (!user?.company_id) return [];

            const { data, error } = await (supabase as any)
                .from('campaigns')
                .select(`
            *,
            insights:campaign_daily_metrics(
              spend,
              impressions,
              clicks,
              conversions
            )
          `)
                .eq('company_id', user.company_id)
                .order('created_at', { ascending: false });

            if (error) throw error;

            return data.map(campaign => {
                const totalSpend = campaign.insights?.reduce((sum, i) => sum + (Number(i.spend) || 0), 0) || 0;
                const totalConversions = campaign.insights?.reduce((sum, i) => sum + (Number(i.conversions) || 0), 0) || 0;
                const totalImpressions = campaign.insights?.reduce((sum, i) => sum + (Number(i.impressions) || 0), 0) || 0;
                const totalClicks = campaign.insights?.reduce((sum, i) => sum + (Number(i.clicks) || 0), 0) || 0;

                return {
                    ...campaign,
                    metrics: {
                        spend: totalSpend,
                        conversions: totalConversions,
                        cpa: totalConversions > 0 ? totalSpend / totalConversions : 0,
                        ctr: totalImpressions > 0 ? (totalClicks / totalImpressions) * 100 : 0
                    }
                };
            });
        },
        enabled: !!user?.company_id,
    });

    const filteredCampaigns = campaigns?.filter(campaign => {
        const matchesSearch = campaign.name.toLowerCase().includes(search.toLowerCase());
        const matchesStatus = statusFilter === 'ALL' || campaign.status === statusFilter;
        return matchesSearch && matchesStatus;
    });

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-8 pb-20"
        >
            {/* Header */}
            <motion.div
                variants={item}
                className="flex flex-col md:flex-row md:items-center justify-between gap-6"
            >
                <div>
                    <div className="flex items-center gap-3 mb-1">
                        <BarChart3 className="w-4 h-4 text-ch-orange" />
                        <span className="text-[10px] font-bold text-ch-orange uppercase tracking-wide">Gestão de Tráfego</span>
                    </div>
                    <h1 className="text-3xl font-bold text-ch-white tracking-tight uppercase">Campanhas Ativas</h1>
                    <p className="text-ch-text-dimmed font-medium mt-1">
                        Monitoramento e otimização de {campaigns?.length || 0} fluxos de aquisição
                    </p>
                </div>

                <div className="flex gap-3">
                    <Button
                        variant="outline"
                        className="h-12 border-white/10 bg-white/5 hover:bg-white/10 text-ch-white font-bold uppercase text-[10px] tracking-widest px-6 rounded-xl transition-all"
                        onClick={() => navigate('/campanhas/nova')}
                    >
                        <Plus className="w-4 h-4 mr-2" />
                        Nova Campanha
                    </Button>
                </div>
            </motion.div>

            {/* Filters */}
            <motion.div
                variants={item}
                className="flex flex-col sm:flex-row gap-4 bg-white/[0.02] p-2 rounded-2xl border border-white/5 backdrop-blur-sm shadow-xl"
            >
                <div className="relative flex-1">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-ch-text-dimmed" />
                    <Input
                        placeholder="BUSCAR CAMPANHA POR NOME OU ID..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="pl-11 h-12 bg-transparent border-none text-ch-white placeholder:text-ch-text-dimmed/50 font-medium focus:ring-0 uppercase text-xs tracking-wide"
                    />
                </div>
                <div className="flex gap-2 p-1">
                    {['ALL', 'ACTIVE', 'PAUSED'].map((status) => (
                        <Button
                            key={status}
                            variant={statusFilter === status ? 'secondary' : 'ghost'}
                            onClick={() => setStatusFilter(status)}
                            className={`h-10 px-6 rounded-xl font-black uppercase text-[10px] tracking-widest transition-all ${statusFilter === status
                                ? 'bg-ch-orange text-ch-black shadow-lg shadow-ch-orange/20'
                                : 'text-ch-text-dimmed hover:text-ch-white hover:bg-white/5'
                                }`}
                        >
                            {status === 'ALL' ? 'Todas' : status === 'ACTIVE' ? 'Ativas' : 'Pausadas'}
                        </Button>
                    ))}
                </div>
            </motion.div>

            {/* Campaign Grid */}
            <div className="grid gap-4">
                <AnimatePresence>
                    {isLoading ? (
                        <div className="flex flex-col items-center justify-center p-32 space-y-4">
                            <div className="relative">
                                <Activity className="w-12 h-12 text-ch-orange animate-pulse opacity-50" />
                                <div className="absolute inset-0 border-4 border-ch-orange/20 border-t-ch-orange rounded-full w-12 h-12 animate-spin" />
                            </div>
                            <span className="text-[10px] font-bold text-ch-text-dimmed uppercase tracking-widest animate-pulse">Carregando Dados...</span>
                        </div>
                    ) : filteredCampaigns?.length === 0 ? (
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            className="text-center py-24 glass rounded-[2.5rem] border-white/5 bg-white/[0.01]"
                        >
                            <div className="w-20 h-20 bg-white/5 rounded-3xl flex items-center justify-center mx-auto mb-6">
                                <Search className="w-8 h-8 text-ch-text-dimmed opacity-50" />
