    ArrowLeft,
    Image,
    Play,
    Loader2,
    Eye,
    MousePointerClick,
    TrendingUp,
    DollarSign,
    Target,
    BarChart3,
    Film,
    FileImage,
    ExternalLink,
    AlertTriangle,
    CheckCircle,
    Clock,
    MoreVertical,
    Pause,
    Zap,
    Sparkles,
    ShieldCheck,
    Type,
    Link as LinkIcon,
    Award,
    Trash2,
